CREATE TABLE process_to_data_asset
(
	id serial,
	process_id integer NOT NULL,
	data_asset_id integer DEFAULT NULL,
	CONSTRAINT pk_process_to_data_asset PRIMARY KEY (id)
	, CONSTRAINT fk_process_to_data_asset_to_process FOREIGN KEY (process_id) REFERENCES process (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_process_to_data_asset_to_data_asset FOREIGN KEY (data_asset_id) REFERENCES data_asset_classifications (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_process_to_data_asset_process ON process_to_data_asset (process_id);
CREATE INDEX i_process_to_data_asset_data_asset ON process_to_data_asset (data_asset_id);
